const email = $input.first().json;

// Parse From field - handle string, object, array formats
let fromName = '';
let fromEmail = '';
const fromRaw = email.from;

if (typeof fromRaw === 'string') {
  const fromMatch = fromRaw.match(/^"?([^"<]+)"?\s*<(.+)>$/);
  fromName = fromMatch ? fromMatch[1].trim() : fromRaw.split('@')[0];
  fromEmail = fromMatch ? fromMatch[2].trim() : fromRaw;
} else if (Array.isArray(fromRaw)) {
  const first = fromRaw[0] || {};
  fromName = first.name || first.address || '';
  fromEmail = first.email || first.address || '';
} else if (fromRaw && typeof fromRaw === 'object') {
  fromName = fromRaw.name || fromRaw.address || '';
  fromEmail = fromRaw.email || fromRaw.address || '';
}

// Fallback: check headers for From
if (!fromEmail) {
  let headerFrom = '';

  if (typeof email.headers === 'object' && !Array.isArray(email.headers)) {
    // n8n Gmail Trigger: headers is a flat object { from: "From: Name <email>", ... }
    headerFrom = email.headers?.from || email.headers?.From || '';
    headerFrom = String(headerFrom).replace(/^From:\s*/i, '').trim();
  } else {
    // Fallback for array-style headers (Gmail API raw)
    const headers = Array.isArray(email.headers) ? email.headers : (email.payload?.headers || []);
    const fromHeader = headers.find(h => h.name?.toLowerCase() === 'from');
    headerFrom = fromHeader ? String(fromHeader.value) : '';
  }

  if (headerFrom) {
    const hMatch = headerFrom.match(/^"?([^"<]+)"?\s*<([^>]+)>$/);
    fromName = hMatch ? hMatch[1].trim() : headerFrom.split('@')[0];
    fromEmail = hMatch ? hMatch[2].trim() : headerFrom;
  }
}

if (!fromName) fromName = fromEmail.split('@')[0] || 'Desconocido';
if (!fromEmail) fromEmail = 'unknown@unknown.com';

// Parse subject - also check flat headers object
const subject = email.subject
  || (typeof email.headers === 'object' && !Array.isArray(email.headers)
      ? (email.headers?.subject || email.headers?.Subject || '').replace(/^Subject:\s*/i, '').trim()
      : '')
  || (email.payload?.headers || []).find(h => h.name?.toLowerCase() === 'subject')?.value
  || 'Sin asunto';

const body = email.text || email.textPlain || email.snippet || '';
const messageId = email.id || '';
const threadId = email.threadId || '';

// Skip automated emails
const skipPatterns = ['noreply', 'no-reply', 'mailer-daemon', 'donotreply', 'notification', 'auto-', 'bounce', '@google.com', '@facebook.com', '@linkedin.com', 'newsletter', 'unsubscribe'];
const isAutomated = skipPatterns.some(p => String(fromEmail).toLowerCase().includes(p));

return [{
  json: {
    fromEmail: String(fromEmail),
    fromName: String(fromName),
    subject: String(subject),
    body: String(body).substring(0, 4000),
    bodySnippet: String(body).substring(0, 600),
    messageId: String(messageId),
    threadId: String(threadId),
    isAutomated,
    toAccount: 'comercial'
  }
}];

const supaResult = $input.first().json;
const approvalId = Array.isArray(supaResult) ? supaResult[0].id : supaResult.id;
const emailData = $('Extraer Categoría').item.json;

const approveUrl = `https://n8n.stratomai.com/webhook/tripath-approve-email?id=${approvalId}`;
const rejectUrl = `https://n8n.stratomai.com/webhook/tripath-reject-email?id=${approvalId}`;

const fromLine = emailData.fromName !== emailData.fromEmail
  ? `${emailData.fromName} <${emailData.fromEmail}>`
  : emailData.fromEmail;

const categoryEmoji = emailData.category === 'operativa' ? '⚙️ OPERATIVA' : '🤝 COMERCIAL';

const text = `✉️ *Nuevo email [${emailData.toAccount}@tripath.es]* ${categoryEmoji}\n\n*De:* ${fromLine}\n*Asunto:* ${emailData.subject}\n\n*Extracto:*\n${emailData.bodySnippet}\n\n---\n⏳ *Sales Manager preparará la respuesta.*\nPulsa Aprobar cuando esté lista.`;

return [{
  json: {
    text: text.substring(0, 4096),
    approveUrl,
    rejectUrl,
    approvalId
  }
}];

const llmResult = $input.first().json;
const rawText = llmResult?.choices?.[0]?.message?.content || '';
const category = rawText.toLowerCase().includes('operativa') ? 'operativa' : 'comercial';

// Pasar todos los datos del email original + category
const emailData = $('Extraer Datos Email').item.json;

return [{
  json: {
    ...emailData,
    category,
    categoryLabel: category === 'comercial' ? '🤝 COMERCIAL' : '⚙️ OPERATIVA'
  }
}];

